// ============================================================
// Process one chunk of grants: AI classify, insert eligible,
// fire-and-forget screener webhook.
// ============================================================

const raw = $input.first().json;
const input = raw.body || raw;
const orgId = input.org_id;
const org = input.org || { id: orgId };
const nicheSummary = input.nicheSummary || '';
const callbackUrl = input.callbackUrl;
const chunkIndex = input.chunk_index || 0;
const totalChunks = input.total_chunks || 1;
const grants = Array.isArray(input.grants) ? input.grants : [];

if (grants.length === 0) {
  return [{ json: { success: true, chunk_index: chunkIndex, inserted: 0, screened: 0, total: 0 } }];
}

const BATCH_SIZE = 15;
const openAiKey = 'REPLACE_ME_OPENAI_KEY';

const supabaseUrl = 'https://fgudhlcktsstwpxwtwzz.supabase.co/rest/v1';
const supabaseKey = 'REPLACE_ME_SUPABASE_SERVICE_KEY';
const supaHeaders = {
  'apikey': supabaseKey,
  'Authorization': 'Bearer ' + supabaseKey,
  'Content-Type': 'application/json',
};
const webhookHeaders = {
  'Content-Type': 'application/json',
  'x-webhook-secret': 'REPLACE_ME_WEBHOOK_SECRET'
};

async function sendStatus(status, stage_message) {
  if (!callbackUrl || !orgId) return;
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: callbackUrl,
      headers: webhookHeaders,
      body: { org_id: orgId, status, stage_message }
    });
  } catch (e) {
    console.error('[Process Chunk]', e && e.message || e);
    throw e;
  }
}

const systemPrompt = `  ========================================
  STEP 1 — CLASSIFY GRANT TYPE
  ========================================
  - federal: Funded by a federal agency (HHS, NIH, NEH, DOL, ED, HUD, USDA,
    DOS/US Mission, etc.) or listed on Grants.gov. grant_state = null.
  - state: Funded by a specific state or a state-level body. Set grant_state
    to the full state name.
  - philanthropic: Private foundation, corporate giving program, family trust,
    community foundation, or nonprofit funder. grant_state = null.

  ========================================
  STEP 1.5 — OPPORTUNITY VALIDITY (reject placeholders)
  ========================================
  A grant is a SPECIFIC funding opportunity with an application path, eligible
  activities, and ideally a deadline or award range. A row that is really just
  a funder profile / homepage is NOT a grant — even if the funder is real and
  well-known.

  Mark eligible=false with reason "not_an_opportunity: <why>" if ANY of these
  apply:
    - Title ends with "Philanthropic Foundation", "Major Philanthropic
      Foundation", "Potential Grant Source", or "Grant Source".
    - Title is just the funder name (e.g. "Ford Foundation") with no program
      attached.
    - Description is a generic foundation overview rather than a specific
      program / RFP.
    - source_url is the funder homepage rather than a program page.
    - awardCeiling/awardFloor are 0 AND there is no deadline AND no
      application instructions.

  ========================================
  STEP 2 — HARD DISQUALIFIERS
  ========================================
  Mark eligible=false and skip remaining steps if the grant explicitly
  restricts applicants to a group the organization is NOT:
    - Specific identity (Native Hawaiian, federally-recognized tribe, HBCU,
      MSI, veterans-only) the org is not.
    - Specific entity type (academic/research institution, state agency,
      local government, tribal government, for-profit, hospital, school
      district, FQHC) the org is not.
    - Specific geographic restriction outside the org's service area.
    - Sector far outside the org core work (basic research, clinical trials,
      animal research, military, space) for a community-services nonprofit.
    - Funding mechanism the org cannot use (P40 / R35 / U54 NIH research
      mechanisms when the org is not a research org).

  ========================================
  STEP 3 — INSUFFICIENT INFO CHECK
  ========================================
  If the grant description is shorter than 100 chars, empty, or does not
  explain purpose / audience / activities → eligible=false,
  reason="insufficient_info: grant description lacks detail".

  Same rule for org profile: if the org has no mission, description,
  executive summary, sector, or programs listed → eligible=false,
  reason="insufficient_info: organization profile is empty".

  ========================================
  STEP 4 — NICHE ALIGNMENT (binary, evidence-based)
  ========================================
  grant_quote and org_quote MUST be grounded in the text actually shown to
  you above. You may paraphrase or summarize, but every claim must be
  traceable to specific content in that text. Do NOT invent facts from
  your training memory of similar grants. Do NOT cite phrases that belong
  to a different grant or a different organization. If the text shown
  does not contain content that establishes direct alignment, output empty
  string for the quote and set niche_aligned=false.

  Mark niche_aligned=true ONLY if ALL of the following hold:

  A. MISSION FIT — there is a verbatim phrase in the org profile that names
     the SAME activity, population, OR outcome the grant funds. The match
     must be at the same level of specificity. Adjacent or sibling causes
     within the same broad sector do NOT count.

     Calibration of what is NOT a match (these are all REJECTS):
       - K-12 education ≠ postsecondary access
       - Teacher preparation ≠ student support
       - STEM research grants ≠ college success programs
       - Health equity research ≠ youth education services
       - Volunteer-engagement / national service ≠ direct programmatic work
       - Foreign exchange / international alumni ≠ domestic services
       - Disabilities employment outcomes ≠ general youth/education work
       - Basic science / federal R&D ≠ community programming

  B. SERVICE PROGRAM FIT — there is a verbatim phrase in the org profile
     (mission / description / executive_summary / programs / supporting
     documents) showing the org currently runs the activity the grant
     funds — not a future intent, not a related capability.
     If the org has NO programs listed AND no operational language in
     mission/description/exec_summary about the grant activity, GATE B
     FAILS automatically — set niche_aligned=false.

  C. POPULATION + GEOGRAPHY MATCH — the grant target population and
     geographic scope must overlap with the org served population and
     service area.

  REJECT EXAMPLE:
    Org mission: "Helping Atlanta Public Schools students access, afford,
                  and earn postsecondary credentials"
    Grant: "FY 2026 AmeriCorps Volunteer Generation Fund — investments in
            volunteer engagement practices"
    Decision: niche_aligned=false. The org serves postsecondary students;
              this grant funds volunteer recruitment infrastructure.
              Different activity. REJECT.

  ========================================
  STEP 5 — FIT SCORE & DISCOVERY BAR
  ========================================
  This is a ROUGH FIRST PASS, not the final decision. A separate downstream
  screener will do detailed multi-dimension scoring. Your job is to
  filter out grants with NO plausible connection to the org while letting
  through anything with a meaningful overlap. Be willing to forward
  "decent but not perfect" matches.

  Score on 0-100:
    85-100: clear direct match.
    65-84:  meaningful overlap — at least one of activity / population /
            outcome aligns; remaining dimensions don't actively conflict.
    50-64:  loose-but-real connection — same broad subsector, partially
            overlapping population, or compatible outcome. Pass to the
            screener; let downstream scoring decide.
    0-49:   off-mission, wrong sector, or restricts to a group the org
            isn't — REJECT.

  PASS (eligible=true) requires ALL of:
    - fit_score >= 50
    - niche_aligned = true
    - grant_quote and org_quote both non-empty and grounded in the
      text shown above

  REJECT (eligible=false) when ANY of these is true:
    - The grant funds an activity in a clearly different sector
      (basic biomedical research, military hardware, ocean technology,
      foreign-affairs exchanges, etc.) and the org is not in that sector.
    - The grant restricts to a population the org does not serve
      (Native nations, veterans-only, international participants only,
      people with disabilities only) and the org doesn't serve that group.
    - The grant's geographic restriction excludes the org.
    - The grant's mechanism is one the org cannot use (NIH P40/R35/U54
      research mechanisms for a non-research org).
    - There is no plausible activity / population / outcome overlap at all.

  When unsure between 45 and 55, lean PASS — the screener will catch
  weak matches with its richer scoring. Don't reject for "imperfect" —
  only reject for "irrelevant."

  ========================================
  OUTPUT FORMAT
  ========================================
  Return ONLY a valid JSON array, one object per input grant, same order:
    {
      "grant_type": "federal" | "state" | "philanthropic",
      "grant_state": "Full state name or null",
      "location_eligible": true | false,
      "niche_aligned": true | false,
      "fit_score": 0-100,
      "eligible": true | false,
      "grant_quote": "verbatim from grant title/description, or empty",
      "org_quote": "verbatim from org profile, or empty",
      "reason": "one-sentence explanation"
    }
  Do not include any text outside the JSON array.
`;

const totalBatches = Math.ceil(grants.length / BATCH_SIZE);
let totalInserted = 0;
let totalScreened = 0;
let newInserts = 0;
let alreadyExisted = 0;

await sendStatus.call(this, 'filtering', 'Matching grants (chunk ' + (chunkIndex + 1) + '/' + totalChunks + ')');

// Cap parallel AI batches at 2 to stay under OpenAI rate limits
const PARALLEL_BATCH_LIMIT = 2;
const batchIndices = Array.from({ length: totalBatches }, (_, b) => b);
for (let p = 0; p < batchIndices.length; p += PARALLEL_BATCH_LIMIT) {
  const slice = batchIndices.slice(p, p + PARALLEL_BATCH_LIMIT);
  await Promise.all(slice.map(async (b) => {
  const start = b * BATCH_SIZE;
  const batch = grants.slice(start, start + BATCH_SIZE);

  const userPrompt = `
Organization:
- ID: ${org.id}
- Location: ${org.geographic_focus ? (Array.isArray(org.geographic_focus) ? org.geographic_focus.join(', ') : org.geographic_focus) : 'Not set'}
- Address: ${org.address || 'Not set'}

Organization Narratives (niche/focus context):
${nicheSummary || 'No narratives available'}

Evaluate EACH grant below against the organization above. For each grant, classify its type, determine location eligibility, and evaluate niche alignment.

Grants:
${JSON.stringify(batch, null, 2)}`;

  // --- AI call with retry-on-429/5xx (handles OpenAI rate limits) ---
  async function callOpenAI(attempt) {
    attempt = attempt || 0;
    try {
      return await helpers.httpRequest({
        method: 'POST',
        url: 'https://api.openai.com/v1/chat/completions',
        headers: {
          'Authorization': 'Bearer ' + openAiKey,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          model: 'gpt-4.1-mini',
          messages: [
            { role: 'system', content: systemPrompt },
            { role: 'user', content: userPrompt }
          ],
          temperature: 0,
        }),
      });
    } catch (e) {
      const code = e.httpCode || e.statusCode || (e.response && e.response.status);
      const msg = String((e && e.message) || '').toLowerCase();
      const is429 = code === 429 || msg.includes('too many requests') || msg.includes('rate limit') || msg.includes('insufficient_quota');
      const is5xx = (code >= 500 && code < 600) || msg.includes('internal server error') || msg.includes('bad gateway') || msg.includes('service unavailable');
      if ((is429 || is5xx) && attempt < 3) {
        const delay = 1000 * Math.pow(2, attempt) + Math.floor(Math.random() * 500);
        await new Promise(function (r) { setTimeout(r, delay); });
        return callOpenAI(attempt + 1);
      }
      if (is429 || is5xx) {
        throw new Error('OpenAI sustained ' + (code || 'failure') + ' after retries: ' + (e && e.message));
      }
      throw e;
    }
  }

  const helpers = this.helpers;
  let parsedResults = [];
  try {
    const aiResponse = await callOpenAI();
    // Strict response-shape check: surface bad shapes loudly.
    if (!aiResponse || typeof aiResponse !== 'object') {
      throw new Error('OpenAI returned non-object response: ' + String(aiResponse).slice(0, 300));
    }
    if (aiResponse.error) {
      const ee = aiResponse.error;
      throw new Error('OpenAI error: type=' + (ee.type || '?') + ' code=' + (ee.code || '?') + ' msg=' + (ee.message || ''));
    }
    if (!aiResponse.choices || !aiResponse.choices[0] || !aiResponse.choices[0].message) {
      throw new Error('OpenAI returned malformed response (no choices): ' + JSON.stringify(aiResponse).slice(0, 400));
    }
    const aiText = aiResponse.choices[0].message.content || '';
    const cleaned = aiText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    const parsed = JSON.parse(cleaned);
    parsedResults = Array.isArray(parsed) ? parsed : [parsed];
  } catch (e) {
    // Re-throw SYSTEMIC OpenAI failures so the Error Notification Handler fires.
    const msg = String((e && e.message) || e || '').toLowerCase();
    // Categorize systemic OpenAI failures so the Slack alert description
    // says the actual cause (quota / auth / rate-limit) instead of generic.
    let _systemicLabel = null;
    if (msg.match(/\b429\b/) || msg.includes('insufficient_quota')) {
      _systemicLabel = 'OpenAI quota exhausted — top up at platform.openai.com/account/billing';
    } else if (msg.match(/\b401\b/) || msg.includes('invalid api key')) {
      _systemicLabel = 'OpenAI auth failure — invalid API key';
    } else if (msg.match(/\b403\b/) || msg.includes('account_deactivated') || msg.includes('billing')) {
      _systemicLabel = 'OpenAI access forbidden — account or billing issue';
    } else if (msg.includes('openai sustained') || msg.includes('too many requests') || msg.includes('rate limit')) {
      _systemicLabel = 'OpenAI rate-limited after retries';
    }
    if (_systemicLabel) {
      throw new Error(_systemicLabel + ': ' + (e && e.message));
    }
    parsedResults = batch.map(() => ({
      grant_type: 'unknown', grant_state: null,
      location_eligible: false, niche_aligned: false,
      eligible: false, reason: 'insufficient_info: AI parse failed, defaulting to ineligible'
    }));
  }

  // --- Build candidates (sync) — passes lexical gates ---
  const _candidates = [];
  batch.forEach((grant, index) => {
    const parsed = parsedResults[index] || {
      grant_type: 'unknown', grant_state: null,
      location_eligible: false, niche_aligned: false,
      eligible: false, reason: 'insufficient_info: no AI result for this grant'
    };
    if (parsed.eligible !== true) return;
    if (parsed.niche_aligned !== true) return;
    const _fit = Number(parsed.fit_score);
    if (!Number.isFinite(_fit) || _fit < 50) return;

    const _gQuoteRaw = String(parsed.grant_quote == null ? '' : parsed.grant_quote).trim();
    const _oQuoteRaw = String(parsed.org_quote   == null ? '' : parsed.org_quote).trim();
    if (!_gQuoteRaw || !_oQuoteRaw) return;

    const _STOP = new Set(['the','a','an','and','or','of','in','on','to','for','by','with','at','as','from','that','this','these','those','is','are','was','were','be','been','being','will','have','has','had','its','their','our','we','they','them','your','his','her','it','also','but','if','than','then','not','no','any','all','some','such','more','most','can','may','must','should','shall','do','does','did','one','two','via','per','only','via','other']);
    function _contentWords(s) {
      const m = String(s).toLowerCase().match(/[a-z][a-z'\-]{2,}/g);
      if (!m) return [];
      const out = [];
      for (let i = 0; i < m.length; i++) if (!_STOP.has(m[i])) out.push(m[i]);
      return out;
    }
    function _coverage(quote, haystack) {
      const words = _contentWords(quote);
      if (words.length < 3) return 0;
      const hay = String(haystack || '').toLowerCase();
      let hit = 0;
      for (let i = 0; i < words.length; i++) if (hay.indexOf(words[i]) !== -1) hit++;
      return hit / words.length;
    }

    const COVERAGE_MIN = 0.6;
    const _grantHay = (grant.title || '') + ' ' + (grant.description || '');
    const _orgHay   = nicheSummary || '';
    if (_coverage(_gQuoteRaw, _grantHay) < COVERAGE_MIN) return;
    if (_coverage(_oQuoteRaw, _orgHay)   < COVERAGE_MIN) return;

    _candidates.push({ grant: grant, parsed: parsed });
  });

  // --- Faithfulness verification (second AI call) ---
  // Some quotes pass the lexical coverage check but are actually
  // hallucinated — same words appearing separately in the source. Ask
  // the model directly whether each quote faithfully summarizes content
  // present in the source. Reject if not.
  let _verified = [];
  if (_candidates.length > 0) {
    const VERIFY_BATCH = 5;
    const verSys = 'You verify whether quotes faithfully represent content actually present in source texts. A quote is FAITHFUL when a careful reader of the source would agree the quote reflects something the source actually says about its topic, activities, or population. A quote is NOT FAITHFUL when it includes facts, activities, populations, programs, or claims not present in the source — even if individual words from the quote happen to appear separately in the source. Return ONLY a JSON array, one object per item in the same order: {"id": "<id>", "grant_quote_faithful": boolean, "org_quote_faithful": boolean}. No prose, no markdown.';

    for (let v = 0; v < _candidates.length; v += VERIFY_BATCH) {
      const slice = _candidates.slice(v, v + VERIFY_BATCH);
      const items = slice.map(function (c, i) {
        return {
          id: String(i),
          grant_text: ((c.grant.title || '') + '. ' + (c.grant.description || '')).slice(0, 2200),
          grant_quote: String(c.parsed.grant_quote || '').slice(0, 400),
          org_text: String(nicheSummary || '').slice(0, 1600),
          org_quote: String(c.parsed.org_quote || '').slice(0, 400),
        };
      });

      let parsedV = null;
      try {
        const resp = await this.helpers.httpRequest({
          method: 'POST',
          url: 'https://api.openai.com/v1/chat/completions',
          headers: { 'Authorization': 'Bearer ' + openAiKey, 'Content-Type': 'application/json' },
          body: JSON.stringify({
            model: 'gpt-4.1-mini',
            messages: [
              { role: 'system', content: verSys },
              { role: 'user',   content: 'Verify each item:\n' + JSON.stringify(items, null, 2) },
            ],
            temperature: 0,
          }),
          json: true,
          timeout: 30000,
        });
        const txt = (resp && resp.choices && resp.choices[0] && resp.choices[0].message && resp.choices[0].message.content) || '[]';
        const cleaned = txt.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
        const arr = JSON.parse(cleaned);
        if (Array.isArray(arr)) parsedV = arr;
      } catch (e) {
        parsedV = null; // fail-closed below
      }

      for (let i = 0; i < slice.length; i++) {
        const v2 = (parsedV && parsedV[i]) || {};
        if (v2.grant_quote_faithful === true && v2.org_quote_faithful === true) {
          _verified.push(slice[i]);
        }
      }
    }
  }

  // --- Push verified candidates to toInsert ---
  const toInsert = [];
  for (let k = 0; k < _verified.length; k++) {
    const grant  = _verified[k].grant;
    const parsed = _verified[k].parsed;
    const description = grant.description || '';

    let deadlineValue = null;
    if (grant.closeDate && grant.closeDate !== 'See listing' && grant.closeDate !== 'Not specified' && grant.closeDate !== 'Rolling') {
      const d = new Date(grant.closeDate);
      if (!isNaN(d.getTime())) {
        const yyyy = d.getUTCFullYear();
        const mm = String(d.getUTCMonth() + 1).padStart(2, '0');
        const dd = String(d.getUTCDate()).padStart(2, '0');
        deadlineValue = yyyy + '-' + mm + '-' + dd + 'T00:00:00.000Z';
      } else {
        deadlineValue = grant.closeDate;
      }
    }

    toInsert.push({
      org_id: org.id,
      central_grant_id: grant.id,
      stage: 'discovery',
      metadata: {
        grant_type: parsed.grant_type || 'unknown',
        grant_state: parsed.grant_state || null,
        location_filter_reason: parsed.reason || '',
        location_eligible: parsed.location_eligible !== false,
        niche_aligned: parsed.niche_aligned !== false,
        fit_score: parsed.fit_score == null ? null : parsed.fit_score,
        grant_quote: parsed.grant_quote || '',
        org_quote: parsed.org_quote || '',
        faithfulness_verified: true,
        priority: 'medium',
      },
      _title: grant.title || '',
      _funder: grant.agency || null,
      _source_url: grant.source_url || grant.link || '',
      _source: (typeof grant.source === 'string' ? grant.source : 'Grant Scanner'),
      _description: description,
      _amount: grant.awardCeiling > 0 ? grant.awardCeiling : null,
      _deadline: deadlineValue,
      _source_id: grant.source_id || grant.oppNum,
    });
  } // <<< forEach closes here

  // --- Insert approved grants (this block is at async level, awaits are legal) ---
  if (toInsert.length > 0) {
    await Promise.all(toInsert.map(async (g) => {
      const supabaseBody = {
        org_id: g.org_id,
        central_grant_id: g.central_grant_id,
        stage: g.stage,
        metadata: g.metadata,
      };
      try {
        const insertedRows = await this.helpers.httpRequest({
          method: 'POST',
          url: supabaseUrl + '/grants?on_conflict=org_id,central_grant_id',
          headers: {
            ...supaHeaders,
            'Prefer': 'return=representation,resolution=ignore-duplicates',
          },
          body: JSON.stringify(supabaseBody),
        });
        if (Array.isArray(insertedRows) && insertedRows.length > 0) {
          g._dbId = insertedRows[0].id;
          g._status = 'new';
          newInserts++;
        } else {
          const existing = await this.helpers.httpRequest({
            method: 'GET',
            url: supabaseUrl + '/grants?org_id=eq.' + encodeURIComponent(g.org_id)
                 + '&central_grant_id=eq.' + encodeURIComponent(g.central_grant_id)
                 + '&select=id&limit=1',
            headers: supaHeaders,
          });
          if (Array.isArray(existing) && existing.length > 0) {
            g._dbId = existing[0].id;
          }
          g._status = 'existing';
          alreadyExisted++;
        }
        totalInserted++;
      } catch (e) {
        const detail = {
    message: e.message,
    statusCode: e.httpCode ?? e.statusCode ?? e.response?.status ?? e.response?.statusCode,
    body: e.response?.body ?? e.response?.data,
    error: e.error,
    cause: e.cause?.response?.body ?? e.cause?.response?.data,
    description: e.description,
    responseText: e.response?.body?.message ?? e.response?.data?.message,
    stack: (e.stack || '').slice(0, 200),
  };
  throw new Error('grants insert failed source_id=' + (g._source_id || 'n/a') + ': ' + JSON.stringify(detail));

      }
    }));
  }

  // --- Screener fan-out (skip throttle, fire per-grant to screen-grant directly) ---
  const screenersToFire = toInsert.filter(g => g._dbId);
  if (screenersToFire.length > 0) {
    await Promise.all(screenersToFire.map(g => {
      const payload = {
        url: g._source_url || '',
        grantid: g._dbId,
        orgId: g.org_id || '',
        grantData: {
          title: g._title || '',
          agency: g._funder || '',
          awardRange: g._amount ? String(g._amount) : 'Not specified',
          deadline: g._deadline || '',
          description: g._description || '',
          source: g._source || '',
          org_id: g.org_id || ''
        }
      };
      return this.helpers.httpRequest({
        method: 'POST',
        url: 'https://n8n.thebrownmine.com/webhook/screen-grant',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
        timeout: 5000,
      }).catch(() => { /* screen-grant returns 202 immediately; ignore failures */ });
    }));
    totalScreened += screenersToFire.length;
  }
  }));
} // <<< for-loop close


return [{
  json: {
    success: true,
    chunk_index: chunkIndex,
    total_chunks: totalChunks,
    total: grants.length,
    inserted: totalInserted,
    new: newInserts,
    existing: alreadyExisted,
    screened: totalScreened,
  }
}];
